<template>
  <v-footer app absolute class="AppFooter transparent">
    <!-------------------------->
    <!---- BOTTOM NAV LINKS ---->
    <!-------------------------->
    <v-col cols="12" class="d-sm-none d-flex justify-space-between">
      <router-link
        v-for="link in links"
        :key="link.routeName"
        :to="{name: link.routeName}"
        style="color: inherit"
      >{{link.text}}</router-link>
    </v-col>

    <!------------------------->
    <!------- COPYRIGHT ------->
    <!------------------------->
    <v-col class="text-left copyright" cols="7">
      © {{ new Date().getFullYear() }} Simone Carletti.
      <span
        class="d-none d-sm-inline"
      >{{ $t("footer.rights") }}</span>
    </v-col>
    <v-col class="text-right" cols="5">
      <router-link :to="{name: 'contact'}" class="pl-3">
        <v-icon>mdi-email-outline</v-icon>
      </router-link>
      <a v-for="link in socialLinks" :key="link.url" :href="link.url" target="_blank" class="pl-3">
        <v-icon>{{link.icon}}</v-icon>
      </a>
    </v-col>
  </v-footer>
</template>

<script>
import { mapState } from "vuex";

export default {
  name: "AppFooter",
  computed: {
    ...mapState(["socialLinks"]),

    links() {
      return [
        {
          routeName: "projects",
          text: this.$t("navbar.links[0]")
        },
        {
          routeName: "photography",
          text: this.$t("navbar.links[1]")
        },
        {
          routeName: "contact",
          text: this.$t("navbar.links[2]")
        }
      ];
    }
  }
};
</script>

<style scoped>
.AppFooter {
  font-family: "ARegular";
}

@media (max-width: 600px) {
  .copyright {
    font-size: 0.9rem;
  }
}
</style>