<template>
  <div class="AppNavbar">
    <v-app-bar app absolute color="transparent" flat>
      <router-link :to="{name: 'home'}" class="logo">Simone Carletti</router-link>

      <v-spacer></v-spacer>

      <a class="nav-icon" ref="navIcon" v-if="$vuetify.breakpoint.xsOnly" @click="openNavDrawer">
        <v-icon>mdi-menu</v-icon>
      </a>
      <template v-else>
        <router-link
          v-for="link in links"
          :key="link.routeName"
          :to="{name: link.routeName}"
          class="link"
        >{{link.text}}</router-link>

        <v-tooltip bottom>
          <template v-slot:activator="{ on, attrs }">
            <a @click="changeLocale" v-bind="attrs" v-on="on" class="link social locale">
              <v-icon>mdi-translate</v-icon>
            </a>
          </template>
          <span>{{ $t('navbar.translationTooltip') }} {{ nextLocale }}</span>
        </v-tooltip>

        <a
          v-for="link in socialLinks"
          :key="link.url"
          :href="link.url"
          target="_blank"
          class="link social"
        >
          <v-icon>{{link.icon}}</v-icon>
        </a>

        <!-- TRANSLATE MENU -->
        <!-- <v-menu offset-y>
          <template #activator="{ on, attrs }">
            <a class="link social" v-bind="attrs" v-on="on">
              <v-icon>mdi-translate</v-icon>
            </a>
          </template>
          <v-list>
            <v-list-item @click="$vuetify.lang.current = 'en'">
              <v-list-item-title>EN</v-list-item-title>
            </v-list-item>
            <v-list-item  @click="$vuetify.lang.current = 'it'">
              <v-list-item-title>IT</v-list-item-title>
            </v-list-item>
          </v-list>
        </v-menu>-->
      </template>
    </v-app-bar>

    <AppNavDrawer
      :open="isNavDrawerOpen"
      @close="closeNavDrawer"
      @changeLocale="changeLocale"
      :links="links"
      :socials="socialLinks"
    ></AppNavDrawer>
  </div>
</template>

<script>
import AppNavDrawer from "@/components/AppNavDrawer.vue";
import { mapState } from "vuex";

export default {
  name: "AppNavbar",
  components: { AppNavDrawer },
  data() {
    return {
      isNavDrawerOpen: false
    };
  },
  computed: {
    ...mapState(["socialLinks"]),

    links() {
      return [
        {
          routeName: "projects",
          text: this.$t("navbar.links[0]")
        },
        {
          routeName: "photography",
          text: this.$t("navbar.links[1]")
        },
        {
          routeName: "contact",
          text: this.$t("navbar.links[2]")
        }
      ];
    },
    nextLocale() {
      let i = this.$store.state.langs.indexOf(this.$i18n.locale);
      return this.$store.state.langs[++i % this.$store.state.langs.length];
    }
  },
  methods: {
    openNavDrawer() {
      this.$refs.navIcon.style.opacity = 0;

      this.isNavDrawerOpen = true;
    },
    closeNavDrawer() {
      this.isNavDrawerOpen = false;

      this.$refs.navIcon.style.opacity = 1;
    },
    // Loop through all locales
    changeLocale() {
      this.$i18n.locale = this.nextLocale;
    }
  }
};
</script>

<style scoped>
.logo {
  font-family: "ABold";
  font-size: 1.6em;
  line-height: 80%;
}

a {
  font-family: "AMedium";
}

a.nav-icon {
  transition: opacity 300ms;
}

.link {
  padding-right: 1em;
  padding-left: 1em;
}

.link.social {
  padding-right: 0.5em;
  padding-left: 0.5em;
}

/* why first-child doesn't work???? */
/* a[href*="github"] {
  padding-left: 1rem !important;
} */

.link:hover,
.link:hover i {
  color: #6c6c6c;
  transition: color 300ms;
}

.locale {
  padding-left: 1rem !important;
}
</style>